// ── 1. Extraer datos del payload ──────────────────────────────────
const body = $input.first().json.body;

if (!body || !body.user) {
  throw new Error('Payload inválido: falta el objeto "user"');
}

const { name, email, plan } = body.user;

// ── 2. Validar que el email existe y tiene formato correcto ────────
if (!email || email.trim() === '') {
  throw new Error('Validación fallida: el campo "email" está vacío o no existe');
}

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(email.trim())) {
  throw new Error(`Validación fallida: formato de email inválido → "${email}"`);
}

// ── 3. Validar campos obligatorios restantes ───────────────────────
if (!name || name.trim() === '') {
  throw new Error('Validación fallida: el campo "name" está vacío o no existe');
}

if (!plan || plan.trim() === '') {
  throw new Error('Validación fallida: el campo "plan" está vacío o no existe');
}

// ── 4. Construir mensaje formateado ────────────────────────────────
const mensaje = `¡Nuevo registro! ${name.trim()} (${email.trim()}) ha contratado el plan ${plan.trim()}.`;

// ── 5. Retornar datos procesados ───────────────────────────────────
return [
  {
    json: {
      mensaje,
      name: name.trim(),
      email: email.trim(),
      plan: plan.trim(),
      timestamp: new Date().toISOString(),
      validado: true
    }
  }
];
